CREATE OR REPLACE VIEW ecomexperts_articulos_update_vASSELECT TOP 100 colores_por_articulo.ml_reference AS sku, colores_por_articulo.ml_name AS titulo, '' AS garantia, 21 AS impuesto, 'default' AS precio_titulo1, dod_articulo = colores_por_articulo.cod_articulo AND piu.cod_color_articulo = colores_por_articulo.cod_color_articuloWHERE (stock_01_14_20_por_talle_v.Talle <> 'X') AND (stock_01_14_20_por_talle_v.Talle IS NOT NULL) AND;;
